diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 4d3de76389c2..7fa81a87b8bb 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3065,6 +3065,7 @@ static Instruction *foldNestedSelects(SelectInst &OuterSelVal,
                             !IsAndVariant ? SelInner : InnerSel.FalseVal);
 }

+
 Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   Value *CondVal = SI.getCondition();
   Value *TrueVal = SI.getTrueValue();
@@ -3138,6 +3139,23 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
                                         /*IsSelectLogical*/ true))
           return replaceInstUsesWith(SI, V);

+    // Fold nested logical-and select of compares:
+    // select (select X, Cmp0, false), Cmp1, false --> select X, fold(Cmp0 & Cmp1), false
+    // if Cmp0 and Cmp1 can be combined.
+    if (auto *InnerSel = dyn_cast<SelectInst>(CondVal)) {
+      Value *InnerCond = InnerSel->getCondition();
+      Value *InnerTrue = InnerSel->getTrueValue();
+      Value *InnerFalse = InnerSel->getFalseValue();
+      if (match(InnerFalse, m_Zero())) {
+        if (auto *ICmp0 = dyn_cast<ICmpInst>(InnerTrue))
+          if (auto *ICmp1 = dyn_cast<ICmpInst>(TrueVal))
+            if (Value *V =
+                    foldAndOrOfICmps(ICmp0, ICmp1, SI, /*IsAnd=*/true,
+                                     /*IsLogical=*/true))
+              return SelectInst::Create(InnerCond, V, Zero);
+      }
+    }
+
     // (A || B) && (C || B) --> (A && C) || B
     if (match(CondVal, m_LogicalOr(m_Value(A), m_Value(B))) &&
         match(TrueVal, m_LogicalOr(m_Value(C), m_Value(D))) &&
@@ -3323,6 +3341,7 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   return nullptr;
 }

+
 // Return true if we can safely remove the select instruction for std::bit_ceil
 // pattern.
 static bool isSafeToRemoveBitCeilSelect(ICmpInst::Predicate Pred, Value *Cond0,

